import os
from src.nodes.base import BaseNode
from src.utils.prism_core import resolve_prism_core

class PrismGetProjectByNameNode(BaseNode):
    name = "Prism: Get Project by Name"
    category = "DCCs"

    def __init__(self):
        super().__init__(use_exec=False)
        self.icon_path = "icons/prism_icon.png"
        self.add_input("core", "any")
        self.add_input("name", "string", widget_type="text", default="")
        self.add_output("project", "dict")
        self.add_output("project_path", "string")
        self.add_output("config_path", "string")
        self.add_output("found", "bool")

    def _scan_root(self, core, root_dir, pipeline_folder, seen, out):
        if not root_dir or not os.path.isdir(root_dir):
            return
        try:
            for entry in os.scandir(root_dir):
                if not entry.is_dir():
                    continue
                cfg = os.path.join(entry.path, pipeline_folder, "pipeline.json")
                if not os.path.exists(cfg) or cfg in seen:
                    continue
                seen.add(cfg)
                name = entry.name
                try:
                    n = core.getConfig("globals", "project_name", configPath=cfg)
                    if n:
                        name = n
                except Exception:
                    pass
                out.append({"configPath": cfg, "name": name, "source": "disk"})
        except PermissionError:
            pass

    def _all_projects(self, core):
        pm = getattr(core, "projects", None)
        known = []
        if pm is not None:
            for method in ("getAvailableProjects", "getRecentProjects"):
                fn = getattr(pm, method, None)
                if callable(fn):
                    try:
                        result = fn()
                        if result:
                            known = list(result)
                            break
                    except Exception:
                        pass
        pipeline_folder = "00_Pipeline"
        if pm is not None:
            try:
                pf = getattr(pm, "getDefaultPipelineFolder", None)
                if callable(pf):
                    pipeline_folder = pf() or pipeline_folder
            except Exception:
                pass
        seen = set()
        projects = []
        for p in known:
            cfg = p.get("configPath", "")
            if cfg:
                seen.add(cfg)
            projects.append(p)
        root_dirs = set()
        for p in known:
            cfg = p.get("configPath", "")
            if cfg:
                root_dirs.add(os.path.dirname(os.path.dirname(os.path.dirname(cfg))))
        if pm is not None:
            fn = getattr(pm, "getDefaultLocalPath", None)
            if callable(fn):
                try:
                    path = fn()
                    if path and os.path.isdir(path):
                        root_dirs.add(path)
                except Exception:
                    pass
        for root in root_dirs:
            self._scan_root(core, root, pipeline_folder, seen, projects)
        return projects

    async def execute(self, inputs):
        core = resolve_prism_core(inputs)
        name = (inputs.get("name") or "").strip()
        empty = {"project": {}, "project_path": "", "config_path": "", "found": False}
        if core is None:
            self.log_error("No PrismCore found.")
            return empty
        if not name:
            self.log_error("No project name provided.")
            return empty
        projects = self._all_projects(core)
        name_lower = name.lower()
        for p in projects:
            if str(p.get("name", "")).lower() == name_lower:
                cfg = p.get("configPath", "")
                prj_path = os.path.dirname(os.path.dirname(cfg)) if cfg else ""
                self.log_info(f"Found project '{p.get('name')}' at {prj_path}")
                return {"project": p, "project_path": prj_path, "config_path": cfg, "found": True}
        self.log_error(f"Project '{name}' not found in {len(projects)} project(s).")
        return empty

def register_node():
    return PrismGetProjectByNameNode
